def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a + 5):
                    coef = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    priority += coef * np.sin(ratio * b / (a + 2)) * np.exp(-b/10)
            priority += np.exp(0.7 * (ratio - 8)) * np.cos(ratio * 1.3) ** 2
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * np.tanh(ratio)
        elif 5 < ratio <= 8:
            temp_sum = 0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 1.5)
                    temp_sum += np.tanh(term) * 1.5
            priority += temp_sum + np.sqrt(ratio) * 15 - np.tanh(ratio - 5) * 4
            if bin_cap < item * 1.5:
                priority -= np.sin(ratio * bin_cap) * 2
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.2) * np.sin(r * ratio * 1.1)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.5) * ((ratio - 1.9) ** m) / m**1.1
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
                priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            else:
                penalty = np.cos(25 * ratio) * 3
                priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 0.9) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2.0)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
            if bin_cap < item * 0.75:
                priority += np.log1p(item * bin_cap) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1.5 / (bin_cap + 5)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
